import sys

def solve(data: str) -> str:
    rows = [line.split(',') for line in data.splitlines() if line.strip()]
    correct = [int(truth) == int(predicted) for _,truth,predicted in rows]
    groups: dict[str, list[bool]] = {}
    for (group,_,_), result in zip(rows, correct):
        groups.setdefault(group, []).append(result)
    overall = sum(correct) / len(correct)
    worst = min(sum(values)/len(values) for values in groups.values())
    return f"overall={overall:.3f} worst_group={worst:.3f}"

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
